Use MAUI's `Window` lifecycle events (`Deactivated`/`Resumed`) paired with `Preferences` for lightweight persistence:

**In your `NotePage.xaml.cs`:**

```csharp
public partial class NotePage : ContentPage
{
    private const string DraftKey = "note_draft";

    public NotePage()
    {
        InitializeComponent();
    }

    protected override void OnAppearing()
    {
        base.OnAppearing();

        // Restore draft
        if (Preferences.ContainsKey(DraftKey))
            NoteEditor.Text = Preferences.Get(DraftKey, string.Empty);

        // Subscribe to lifecycle events
        var window = Application.Current?.Windows.FirstOrDefault();
        if (window is not null)
        {
            window.Deactivated += OnAppBackgrounded;
            window.Resumed += OnAppResumed;
        }
    }

    protected override void OnDisappearing()
    {
        base.OnDisappearing();

        var window = Application.Current?.Windows.FirstOrDefault();
        if (window is not null)
        {
            window.Deactivated -= OnAppBackgrounded;
            window.Resumed -= OnAppResumed;
        }
    }

    private void OnAppBackgrounded(object? sender, EventArgs e)
    {
        SaveDraft();
    }

    private void OnAppResumed(object? sender, EventArgs e)
    {
        // Optionally re-read (useful if another process modified storage)
        NoteEditor.Text = Preferences.Get(DraftKey, string.Empty);
    }

    private void SaveDraft()
    {
        Preferences.Set(DraftKey, NoteEditor.Text ?? string.Empty);
    }

    // Call this when the user explicitly saves/submits
    public void ClearDraft()
    {
        Preferences.Remove(DraftKey);
    }
}
```

**Key points:**

| Concept | Detail |
|---|---|
| **`Window.Deactivated`** | Fires when the app loses focus / goes to background |
| **`Window.Resumed`** | Fires when the app returns to foreground |
| **`Preferences`** | Simple key-value store backed by platform-native storage (SharedPreferences on Android, NSUserDefaults on iOS) |
| **Cleanup** | Always unsubscribe in `OnDisappearing` to avoid leaks |

For larger drafts (images, rich text), swap `Preferences` for `SecureStorage` or a file via `FileSystem.AppDataDirectory`. `Preferences` is best for small strings like note text.
